static bool ext_scr_btn_hd_scene_num(int btn_evt)
{
	int8_t(*trigger)(int8_t)=scene_procedure[scene_sel].trigger;
	bool resp=false;
	static uint8_t hld[4];
	if(BTN_IS_PRESS(btn_evt)) { // press
		int8_t idx=-1;
		switch(BTN_IDX(btn_evt))
		{
		case 1:
		case 12:
			if(NULL!=trigger && 0!=trigger(0)) { trigger(-trigger(0)); app_proceed(); }
			ext_scr_chg_scene();
			resp=true;
			break;
		case 5: idx=0; break;
		case 6: idx=1; break;
		case 7: idx=2; break;
		case 8: idx=3; break;
		case 9:
		case 10: chg_number_cast_auto();
		}

		if(0<=idx) {
			hld[idx]=0;
			numcst_setval(idx,1001);
		}
	}
	else if(BTN_IS_RELEASE(btn_evt)) { // release
	}
	else if(BTN_IS_HOLD(btn_evt)) { // hold
		int8_t idx=-1;
		switch(BTN_IDX(btn_evt))
		{
		case 5: idx=0; break;
		case 6: idx=1; break;
		case 7: idx=2; break;
		case 8: idx=3; break;
		}

		if(0<=idx) {
			numcst_setval(idx, 1000+((hld[idx]<5)?1:((hld[idx]<11)?3:((hld[idx]<18)?7:((hld[idx]<26)?13:23)))));
			if(++hld[idx]>64) hld[idx]--;
		}
	}

	return resp;
}


