static bool ext_scr_btn_hd_scene_env(int btn_evt)
{
	int8_t(*trigger)(int8_t)=scene_procedure[scene_sel].trigger;
	bool resp=false;
	if(BTN_IS_PRESS(btn_evt)) { // press
		switch(BTN_IDX(btn_evt))
		{
		case 1:
		case 12:
			if(NULL!=trigger && 0!=trigger(0)) {
				trigger(-trigger(0)); app_proceed();
			}
			ext_scr_chg_scene();
			resp=true;
			break;
		}
	}
	else if(BTN_IS_RELEASE(btn_evt)) { // release
	}
	else if(BTN_IS_HOLD(btn_evt)) { // hold
	}

	return resp;
}


