/* Extracted: handles BTN 12 press/release/hold for task scenes (snd, rcv).
 * Manages task_btn_tgr counter for hold-to-start/stop task logic.
 * Returns true if the event was consumed.
 */
static bool ext_scr_task_btn_hold(int btn_evt)
{
	int8_t(*trigger)(int8_t) = scene_procedure[scene_sel].trigger;
	bool resp = false;

	if(BTN_IS_PRESS(btn_evt)) {
		switch(BTN_IDX(btn_evt)) {
		case 12:
			task_btn_tgr=1;
			resp=true;
			break;
		}
	}
	else if(BTN_IS_RELEASE(btn_evt)) {
		switch(BTN_IDX(btn_evt)) {
		case 12:
			if(task_btn_tgr && 2>task_btn_tgr) {
				task_btn_tgr=0;
				if(NULL==trigger || 0==trigger(0)) ext_scr_chg_scene();
			}
			resp=true;
			break;
		}
	}
	else if(BTN_IS_HOLD(btn_evt)) {
		switch(BTN_IDX(btn_evt)) {
		case 12:
			if(task_btn_tgr) {
				if(3==task_btn_tgr++) {
					task_btn_tgr=0;
					int tgr_state=(NULL!=trigger)?trigger(0):0;
					if(NULL==trigger ||(NULL!=trigger && 0==tgr_state)) { trigger(1); app_proceed(); }
					else if(0!=tgr_state) { trigger(-tgr_state); app_proceed(); }
				}
			}
			resp=true;
			break;
		}
	}
	return resp;
}

static int resource_sort_cmp(const void * arga_p, const void * argb_p)
{
	RESOURCE_xST * a_p=STRUCT_SECTION_START(scr_resource)+(*(uint8_t *)arga_p);
	RESOURCE_xST * b_p=STRUCT_SECTION_START(scr_resource)+(*(uint8_t *)argb_p);
	
	return a_p->res_idx - b_p->res_idx;
}

